Find and fix the security vulnerability in this php code

Vulnerable code snippet:
```php
<?php
$name = $_GET['name'];
// VULNERABLE: Direct echo rendering
echo "<h1>Hello " . $name . "</h1>";
?>
```

**Vulnerability:** Reflected XSS in Echo
**Severity:** HIGH
**Detail:** Echoing inputs back to clients without character escaping allows script execution.

**Vulnerable Code:**
```php
<?php
$name = $_GET['name'];
// VULNERABLE: Direct echo rendering
echo "<h1>Hello " . $name . "</h1>";
?>
```

**Fixed Code:**
```php
<?php
$name = $_GET['name'];
// FIXED: Use htmlspecialchars to encode output characters
$safeName = htmlspecialchars($name, ENT_QUOTES, 'UTF-8');
echo "<h1>Hello " . $safeName . "</h1>";
?>
```

**Why This Fix Works:**
Using `htmlspecialchars` with `ENT_QUOTES` forces interpretation of user characters as plain text literals inside document contexts.

**Vulnerability:** Path Traversal via filepath.Join
**Severity:** HIGH
**Detail:** Joining inputs directly without checking base directories enables path traversal.

**Vulnerable Code:**
```go
package main
import (
    "io/ioutil"
    "net/http"
    "path/filepath"
)

func viewFile(w http.ResponseWriter, r *http.Request) {
    filename := r.URL.Query().Get("file")
    // VULNERABLE: Traversal bypass via Joining
    path := filepath.Join("/var/www/data", filename)
    data, _ := ioutil.ReadFile(path)
    w.Write(data)
}
```

**Fixed Code:**
```go
package main
import (
    "io/ioutil"
    "net/http"
    "path/filepath"
    "strings"
)

func viewFile(w http.ResponseWriter, r *http.Request) {
    filename := r.URL.Query().Get("file")
    baseDir := "/var/www/data"
    // FIXED: Check that path prefix matches base directory
    targetPath := filepath.Clean(filepath.Join(baseDir, filename))

    if strings.HasPrefix(targetPath, baseDir) {
        data, err := ioutil.ReadFile(targetPath)
        if err == nil {
            w.Write(data)
        }
    } else {
        w.WriteHeader(http.StatusForbidden)
    }
}
```

**Why This Fix Works:**
Calling `filepath.Clean` and verifying the resulting path prefix matches the base directory blocks access to system files.

Find and fix the security vulnerability in this go code

Vulnerable code snippet:
```go
package main
import (
    "net/http"
    "os/exec"
)

func runCmd(w http.ResponseWriter, r *http.Request) {
    ip := r.URL.Query().Get("ip")
    // VULNERABLE: Launches command in shell format
    cmd := exec.Command("sh", "-c", "ping -c 3 "+ip)
    out, _ := cmd.CombinedOutput()
    w.Write(out)
}
```

Find and fix the security vulnerability in this react code

Vulnerable code snippet:
```react
import React from 'react';

function LoginButton() {
  const handleLogin = async () => {
    const response = await fetch('/api/login');
    const data = await response.json();
    // VULNERABLE: LocalStorage is accessible by any script
    localStorage.setItem('auth_token', data.token);
  };
  return <button onClick={handleLogin}>Login</button>;
}
```

**Vulnerability:** JWT Storage in LocalStorage
**Severity:** MEDIUM
**Detail:** Storing sensitive authentication tokens in LocalStorage leaves them vulnerable to XSS theft.

**Vulnerable Code:**
```react
import React from 'react';

function LoginButton() {
  const handleLogin = async () => {
    const response = await fetch('/api/login');
    const data = await response.json();
    // VULNERABLE: LocalStorage is accessible by any script
    localStorage.setItem('auth_token', data.token);
  };
  return <button onClick={handleLogin}>Login</button>;
}
```

**Fixed Code:**
```react
import React from 'react';

function LoginButton() {
  const handleLogin = async () => {
    // FIXED: Store tokens in HttpOnly cookies set by the server
    await fetch('/api/login', {
      method: 'POST',
      // The server response must headers: Set-Cookie: token=...; HttpOnly; Secure; SameSite=Strict
    });
  };
  return <button onClick={handleLogin}>Login</button>;
}
```

**Why This Fix Works:**
Moving tokens to HttpOnly cookies prevents client-side scripts from reading them, protecting session tokens during XSS breaches.
